sp_widget.client_script:
api.controller=function($rootScope, $scope, $timeout, $sce, spUtil, $log, $location, i18n) {
  /* widget controller */
  var c = this;
	$scope.dtech_tasker_common = x_153465_discovert.dtech_tasker_common;
	var shared = {};
	main();

	function main(){
		if(c.data.appContext==$scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.TASK){
			loadTaskHeader();
		}
	}
	c.widget.changeAppContext=function(context){
		c.data.appContext=context;
	};

	function loadTaskHeader(){
		var tasker_task_header_wp = {
			// not sure if we need any params
			shared: shared
		};
		c.data.tasker_task_headers = [];

		spUtil.get('dt_tasker_task_header', tasker_task_header_wp).then(function(response){
			var tasker_task_header_widget = response;
			c.data.tasker_task_headers.push(tasker_task_header_widget);
		});
	}
};

